import{_ as r,o,c as s,ay as n}from"./chunks/framework.-lzFfN-z.js";const a="/CoreFront-EndConcepts/httpsSecond.jpg",e="/CoreFront-EndConcepts/httpsThird.jpg",l="/CoreFront-EndConcepts/httpsFourth.jpg",i="/CoreFront-EndConcepts/httpsFifth.jpg",g="/CoreFront-EndConcepts/middlePerson.png",d="/CoreFront-EndConcepts/https.webp",_=JSON.parse('{"title":"HTTPS 协议","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/https.md","filePath":"networkAndBrowsers/https.md","lastUpdated":1779843930000}'),h={name:"networkAndBrowsers/https.md"};function T(p,t,c,u,S,P){return o(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="https-协议" tabindex="-1">HTTPS 协议 <a class="header-anchor" href="#https-协议" aria-label="Permalink to &quot;HTTPS 协议&quot;">​</a></h1><h2 id="_1-什么是-https" tabindex="-1">1. 什么是 HTTPS？ <a class="header-anchor" href="#_1-什么是-https" aria-label="Permalink to &quot;1. 什么是 HTTPS？&quot;">​</a></h2><p><strong>HTTPS</strong>（HyperText Transfer Protocol Secure，超文本传输安全协议）并不是一个全新的协议，而是 <strong>HTTP + SSL/TLS</strong> 的组合。</p><p>简单来说，HTTP 协议的数据是明文传输的，而 HTTPS 在 HTTP 的应用层和 TCP 的传输层之间，加入了一个安全套接字层（SSL/TLS），负责对传输的数据进行加密、身份验证和完整性保护。</p><ul><li><strong>默认端口：</strong> HTTPS 的默认端口是 <code>443</code>（HTTP 是 <code>80</code>）。</li><li><strong>网址前缀：</strong> URL 以 <code>https://</code> 开头。</li></ul><h2 id="_2-为什么需要-https-http-的三大风险" tabindex="-1">2. 为什么需要 HTTPS？（HTTP 的三大风险） <a class="header-anchor" href="#_2-为什么需要-https-http-的三大风险" aria-label="Permalink to &quot;2. 为什么需要 HTTPS？（HTTP 的三大风险）&quot;">​</a></h2><p>在没有 HTTPS 之前，互联网上的数据几乎都是“裸奔”的，这就带来了致命的安全问题：</p><ul><li><strong>窃听风险 (Eavesdropping)</strong>：黑客可以在数据传输的任何节点（如公共 WiFi、运营商路由器）截获你的账号密码。</li><li><strong>篡改风险 (Tampering)</strong>：黑客可以修改你收到的数据，比如在网页中插入广告，或者将你转账的账号改成他自己的（中间人攻击）。</li><li><strong>伪装风险 (Pretending)</strong>：你无法确认你访问的银行网站是不是真的银行，黑客可以搭建一个一模一样的“钓鱼网站”骗取你的信息。</li></ul><p><strong>HTTPS 的三大防线</strong> 就是专门对付这三个风险的：</p><ul><li><strong>加密 (Encryption)</strong> -&gt; 防窃听</li><li><strong>数据签名 (Data Integrity)</strong> -&gt; 防篡改</li><li><strong>数字证书 (Digital Certificate)</strong> -&gt; 防伪装</li></ul><h2 id="_3-https-的核心原理-混合加密机制" tabindex="-1">3. HTTPS 的核心原理：混合加密机制 <a class="header-anchor" href="#_3-https-的核心原理-混合加密机制" aria-label="Permalink to &quot;3. HTTPS 的核心原理：混合加密机制&quot;">​</a></h2><p>HTTPS 为了同时兼顾<strong>安全性</strong>和<strong>性能</strong>，采用了一种非常巧妙的“混合加密”机制。要理解它，必须先懂两种基础加密方式：</p><h3 id="_3-1-对称加密-symmetric-encryption" tabindex="-1">3.1 对称加密 (Symmetric Encryption) <a class="header-anchor" href="#_3-1-对称加密-symmetric-encryption" aria-label="Permalink to &quot;3.1 对称加密 (Symmetric Encryption)&quot;">​</a></h3><ul><li><strong>原理</strong>：加密和解密使用<strong>同一把钥匙（密钥）</strong>。</li></ul><p><img src="'+a+'" alt="Logo" data-zoomable="true"></p><ul><li><strong>特点</strong>：加密速度极快，适合加密大量数据。</li><li><strong>致命弱点</strong>：如何安全地把这把“钥匙”交给对方？如果黑客在传输钥匙的过程中截获了它，加密就形同虚设了。</li></ul><p><img src="'+e+'" alt="Logo" data-zoomable="true"></p><h3 id="_3-2-非对称加密-asymmetric-encryption" tabindex="-1">3.2 非对称加密 (Asymmetric Encryption) <a class="header-anchor" href="#_3-2-非对称加密-asymmetric-encryption" aria-label="Permalink to &quot;3.2 非对称加密 (Asymmetric Encryption)&quot;">​</a></h3><ul><li><strong>原理</strong>：拥有<strong>两把钥匙</strong>：一把公钥（Public Key），一把私钥（Private Key）。 <ul><li><strong>公钥</strong>是公开的，任何人都可以获取。</li><li><strong>私钥</strong>是自己死死捂住的，绝对不外传。</li><li><strong>核心法则</strong>：用公钥加密的数据，<strong>只有</strong>对应的私钥才能解密。</li></ul></li></ul><p><img src="'+l+'" alt="Logo" data-zoomable="true"></p><ul><li><strong>特点</strong>：解决了密钥分发的问题，非常安全。</li><li><strong>致命弱点</strong>：加密/解密速度极慢（比对称加密慢几百倍甚至上千倍），只适合加密非常少量的数据。</li></ul><p><img src="'+i+'" alt="Logo" data-zoomable="true"></p><h3 id="_3-3-https-的混合加密-扬长避短" tabindex="-1">3.3 HTTPS 的混合加密（扬长避短） <a class="header-anchor" href="#_3-3-https-的混合加密-扬长避短" aria-label="Permalink to &quot;3.3 HTTPS 的混合加密（扬长避短）&quot;">​</a></h3><p>HTTPS 完美地结合了这两者：</p><ul><li><strong>阶段一（非对称加密用于“交换钥匙”）：</strong> 客户端和服务器在正式通信前，利用非对称加密（安全但慢），安全地协商并传递一把<strong>随机生成的“对称密钥（会话密钥）”</strong>。</li><li><strong>阶段二（对称加密用于“正式通信”）：</strong> 钥匙交换成功后，双方就用这把“对称密钥”来加密真正要传输的大量数据（速度快）。</li></ul><p>简单来说：<strong>用非对称加密来加密“对称密钥”，用对称密钥来加密“实际数据”。</strong></p><h2 id="_4-防伪装的利器-数字证书与-ca-机构" tabindex="-1">4. 防伪装的利器：数字证书与 CA 机构 <a class="header-anchor" href="#_4-防伪装的利器-数字证书与-ca-机构" aria-label="Permalink to &quot;4. 防伪装的利器：数字证书与 CA 机构&quot;">​</a></h2><p>即使有了混合加密，还面临一个问题：黑客可以冒充服务器，发给你一个<strong>假的公钥</strong>。当你用这个假公钥加密了数据，黑客用自己的私钥就能解开了。我们假设不存在认证机构，任何人都可以制作证书，这带来的安全风险便是经典的 <strong>中间人攻击 (MITM)</strong> 问题。</p><p><img src="'+g+'" alt="Logo" data-zoomable="true"></p><p>为了解决“我是我”的问题，HTTPS 引入了 <strong>CA 机构（Certificate Authority，证书颁发机构）</strong> 和 <strong>数字证书</strong>。</p><ul><li><strong>CA 的作用</strong>：CA 就像互联网世界的“公安局”。网站站长需要把自己的公钥和身份信息提交给 CA，CA 审核通过后，会用 CA 自己的私钥对这些信息进行<strong>数字签名</strong>，打包成一个“数字证书”发给网站。</li><li><strong>证书的内容</strong>：包含网站域名、网站公钥、证书有效期、签发该证书的 CA 机构名称等。</li><li><strong>浏览器如何验证</strong>：世界上权威的 CA 机构的公钥，早就预装在了你的操作系统和浏览器中。当你访问网站时，网站会出示它的证书。你的浏览器会用内置的 CA 公钥去验证这个证书的数字签名。如果验证通过，就证明这个网站的公钥是真实的，不是黑客伪造的。</li></ul><h2 id="_5-https-的建立过程-tls-握手-tls-handshake" tabindex="-1">5. HTTPS 的建立过程（TLS 握手，TLS Handshake） <a class="header-anchor" href="#_5-https-的建立过程-tls-握手-tls-handshake" aria-label="Permalink to &quot;5. HTTPS 的建立过程（TLS 握手，TLS Handshake）&quot;">​</a></h2><p>这发生在 TCP 三次握手<strong>之后</strong>，真正的 HTTP 数据传输<strong>之前</strong>。这是一个非常复杂的过程，我们简化来看最核心的步骤（以常见的 RSA 密钥交换为例）：</p><ol><li><strong>Client Hello (客户端打招呼)</strong>： <ul><li>客户端向服务器发送请求，包含：客户端支持的 TLS 版本、支持的加密算法套件（Cipher Suites），以及一个<strong>客户端生成的随机数 (Random1)</strong>。</li></ul></li><li><strong>Server Hello (服务器回应)</strong>： <ul><li>服务器从中选择一个自己也支持的加密算法。</li><li>生成一个<strong>服务器端的随机数 (Random2)</strong> 并发送给客户端。</li><li><strong>最重要的一步</strong>：服务器将自己的**数字证书（包含公钥）**发送给客户端。</li></ul></li><li><strong>Certificate Verification (客户端验证证书)</strong>： <ul><li>浏览器验证证书的合法性（是否过期、CA 是否受信任、域名是否匹配）。如果验证失败，浏览器会弹出一个大大的红字警告（“您的连接不是私密连接”）。</li></ul></li><li><strong>Pre-master Secret (生成预主密钥)</strong>： <ul><li>如果证书验证通过，客户端会生成<strong>第三个随机数 (Pre-master Secret)</strong>。</li><li>客户端用证书里的<strong>服务器公钥</strong>对这个 Pre-master Secret 进行加密，并发送给服务器。</li></ul></li><li><strong>生成会话密钥 (Session Key)</strong>： <ul><li>服务器收到密文后，用自己的<strong>私钥</strong>解密，得到 Pre-master Secret。</li><li><strong>奇迹发生</strong>：现在客户端和服务器手里都有了三个相同的随机数（Random1 + Random2 + Pre-master Secret）。双方利用这三个随机数，通过相同的算法，<strong>各自在本地计算出了一把相同的“对称密钥（会话密钥）”</strong>。</li></ul></li><li><strong>加密通信开始</strong>： <ul><li>钥匙协商完毕，双方互相发送一个 <code>Finished</code> 消息，表示握手结束。</li><li>之后所有的 HTTP 请求和响应，都将使用这把协商好的<strong>会话密钥进行对称加密</strong>传输。</li></ul></li></ol><p><img src="'+d+'" alt="Logo" data-zoomable="true"></p><h2 id="_6-http-与-https-的核心对比" tabindex="-1">6. HTTP 与 HTTPS 的核心对比 <a class="header-anchor" href="#_6-http-与-https-的核心对比" aria-label="Permalink to &quot;6. HTTP 与 HTTPS 的核心对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>HTTP</th><th>HTTPS</th></tr></thead><tbody><tr><td><strong>全称</strong></td><td>超文本传输协议</td><td>超文本传输安全协议</td></tr><tr><td><strong>安全性</strong></td><td>明文传输，极不安全</td><td>密文传输，极度安全</td></tr><tr><td><strong>端口号</strong></td><td><code>80</code></td><td><code>443</code></td></tr><tr><td><strong>连接速度</strong></td><td>快（仅需 TCP 三次握手）</td><td>较慢（TCP 三次握手 + TLS 握手）</td></tr><tr><td><strong>证书成本</strong></td><td>免费</td><td>通常需要向 CA 机构付费申请（也有 Let&#39;s Encrypt 等免费方案）</td></tr><tr><td><strong>SEO 表现</strong></td><td>一般</td><td>搜索引擎（如 Google, Baidu）会优先收录和提升 HTTPS 网站的排名</td></tr></tbody></table><h2 id="_7-常见问题-faq-与面试题" tabindex="-1">7. 常见问题 (FAQ) 与面试题 <a class="header-anchor" href="#_7-常见问题-faq-与面试题" aria-label="Permalink to &quot;7. 常见问题 (FAQ) 与面试题&quot;">​</a></h2><h3 id="_7-1-http-和-https-的根本区别是什么" tabindex="-1">7.1 HTTP 和 HTTPS 的根本区别是什么？ <a class="header-anchor" href="#_7-1-http-和-https-的根本区别是什么" aria-label="Permalink to &quot;7.1 HTTP 和 HTTPS 的根本区别是什么？&quot;">​</a></h3><ul><li><strong>安全性</strong>：HTTP 明文传输，不安全；HTTPS 是加密传输，安全。</li><li><strong>端口</strong>：HTTP 默认使用 80 端口；HTTPS 默认使用 443 端口。</li><li><strong>性能/耗时</strong>：HTTPS 因为需要进行 TLS 握手和加解密计算，建立连接的过程比 HTTP 慢，对服务器 CPU 资源的消耗也略大。</li><li><strong>费用</strong>：HTTPS 需要向 CA 机构申请数字证书，高级别的证书通常需要付费。</li></ul><h3 id="_7-2-为什么-https-不全程使用非对称加密" tabindex="-1">7.2 为什么 HTTPS 不全程使用非对称加密？ <a class="header-anchor" href="#_7-2-为什么-https-不全程使用非对称加密" aria-label="Permalink to &quot;7.2 为什么 HTTPS 不全程使用非对称加密？&quot;">​</a></h3><ul><li><strong>性能极差</strong>。非对称加密（如 RSA）的加解密算法极其复杂，非常耗费 CPU 资源，速度极慢。如果网页上的每一张图片、每一段文字都用非对称加密，服务器会崩溃，用户的网页加载速度也会慢到无法忍受。</li></ul><h3 id="_7-3-如果-ca-机构被黑客攻破了怎么办" tabindex="-1">7.3 如果 CA 机构被黑客攻破了怎么办？ <a class="header-anchor" href="#_7-3-如果-ca-机构被黑客攻破了怎么办" aria-label="Permalink to &quot;7.3 如果 CA 机构被黑客攻破了怎么办？&quot;">​</a></h3><ul><li>这是一个系统性的灾难（虽然发生概率极低）。如果黑客拿到了 CA 的私钥，他就可以随意签发伪造的合法证书。一旦发现这种情况，操作系统和浏览器厂商会立即将该 CA 从信任列表中<strong>吊销（Revoke）</strong>，所有由该 CA 签发的证书将瞬间失效。历史上有过几次类似事件（如 DigiNotar 事件），导致该 CA 公司直接破产。</li></ul><h3 id="_7-4-我自己用-openssl-生成一个证书-自签发证书-可以用吗" tabindex="-1">7.4 我自己用 OpenSSL 生成一个证书（自签发证书）可以用吗？ <a class="header-anchor" href="#_7-4-我自己用-openssl-生成一个证书-自签发证书-可以用吗" aria-label="Permalink to &quot;7.4 我自己用 OpenSSL 生成一个证书（自签发证书）可以用吗？&quot;">​</a></h3><ul><li><strong>可以使用，但不受信任</strong>。你可以自己生成公私钥和证书，用来加密数据是没问题的。但是，因为你不是权威的 CA 机构（浏览器不认识你），当用户访问你的网站时，浏览器依然会弹出大红色的安全警告。这种证书通常只用于公司内部的测试环境。</li></ul><h3 id="_7-5-什么是中间人攻击-mitm-https-能防住吗" tabindex="-1">7.5 什么是中间人攻击（MITM），HTTPS 能防住吗？ <a class="header-anchor" href="#_7-5-什么是中间人攻击-mitm-https-能防住吗" aria-label="Permalink to &quot;7.5 什么是中间人攻击（MITM），HTTPS 能防住吗？&quot;">​</a></h3><ul><li><strong>原理</strong>：黑客在你和服务器之间拦截请求，对你伪装成服务器，对服务器伪装成你。</li><li><strong>HTTPS 可以完美防御</strong>。关键在于<strong>数字证书的验证机制</strong>。如果黑客拦截了请求并给了你一个他自己伪造的公钥（证书），由于这个证书没有经过权威 CA 签名，你的浏览器在验证时就会报错并阻止连接，从而粉碎了攻击。</li></ul><h3 id="_7-6-ssl-和-tls-到底是什么关系" tabindex="-1">7.6 SSL 和 TLS 到底是什么关系？ <a class="header-anchor" href="#_7-6-ssl-和-tls-到底是什么关系" aria-label="Permalink to &quot;7.6 SSL 和 TLS 到底是什么关系？&quot;">​</a></h3><ul><li><strong>SSL (Secure Sockets Layer)</strong>：是最早由网景公司开发的安全协议，到了 3.0 版本后被标准化。</li><li><strong>TLS (Transport Layer Security)</strong>：是 SSL 的继任者和升级版。SSL 3.0 被标准化后，更名为 TLS 1.0。现在互联网上广泛使用的是 TLS 1.2 和 TLS 1.3，早期的 SSL 版本因为存在严重漏洞已经被完全废弃。大家常说的“配置 SSL 证书”，实际上配置的都是 TLS。</li></ul>',50)])])}const H=r(h,[["render",T]]);export{_ as __pageData,H as default};
